1649     // Don't introduce poison into div/rem.
1650     if (llvm::is_contained(OldMask, PoisonMaskElem) && BO->isIntDivRem())
1651       return false;
1652     IsCommutative = BinaryOperator::isCommutative(BO->getOpcode());
1653   } else if (match(LHS, m_Cmp(Pred, m_Value(X), m_Value(Y))) &&
1654              match(RHS, m_SpecificCmp(Pred, m_Value(Z), m_Value(W)))) {
1655     IsCommutative = cast<CmpInst>(LHS)->isCommutative();
