149 /// Return the source operand of a potentially bitcasted value. If there is no
150 /// bitcast, return the input value itself.
151 static Value *peekThroughBitcasts(Value *V) {
152   while (auto *BitCast = dyn_cast<BitCastInst>(V))
153     V = BitCast->getOperand(0);
154   return V;
155 }
